#include <bits/stdc++.h>
using namespace std;
int n,m,a[100005];
bool check(int x){
    int sum=0,cnt=1;
    for(int i=1;i<=n;i++){
        if(a[i]+sum<=x)
            sum+=a[i];
        else
            sum=a[i],cnt++;
    }
    return cnt<=m;
}
int main(){
    scanf("%d%d",&n,&m);
    int l=0,r=1e9;
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        l=max(l,a[i]);
    }
    while(l<r){
        int mid=l+r>>1;
        if(check(mid))
            r=mid;
        else
            l=mid+1;
    }
    printf("%d",l);
    return 0;
}
